package xyz.erupt.core.controller;import com.google.gson.JsonObject;import jakarta.transaction.Transactional;import lombok.RequiredArgsConstructor;import lombok.SneakyThrows;import lombok.extern.slf4j.Slf4j;import org.springframework.context.ApplicationEventPublisher;import org.springframework.web.bind.annotation.*;import xyz.erupt.annotation.fun.PowerObject;import xyz.erupt.core.annotation.EruptRecordOperate;import xyz.erupt.core.annotation.EruptRouter;import xyz.erupt.core.config.GsonFactory;import xyz.erupt.core.constant.EruptRestPath;import xyz.erupt.core.event.EruptAddEvent;import xyz.erupt.core.invoke.DataProcessorManager;import xyz.erupt.core.invoke.DataProxyInvoke;import xyz.erupt.core.naming.EruptRecordNaming;import xyz.erupt.core.service.EruptCoreService;import xyz.erupt.core.service.EruptModifyService;import xyz.erupt.core.util.Erupts;import xyz.erupt.core.view.EruptModel;import xyz.erupt.core.view.R;import java.util.List;/** * Erupt 对数据的增删改查 * * @author YuePeng * date 9/28/18. */@Slf4j@RestController@RequestMapping(EruptRestPath.ERUPT_DATA_MODIFY)@RequiredArgsConstructorpublic class EruptModifyController {    private final EruptModifyService eruptModifyService;    private final ApplicationEventPublisher applicationEventPublisher;    @PostMapping({"/{erupt}"})    @EruptRecordOperate(value = "INSERT", dynamicConfig = EruptRecordNaming.class)    @EruptRouter(skipAuthIndex = 3, authIndex = 1, verifyType = EruptRouter.VerifyType.ERUPT, highSafe = true)    public R<Void> addEruptData(@PathVariable("erupt") String erupt, @RequestBody JsonObject data) {        EruptModel eruptModel = EruptCoreService.getErupt(erupt);        Erupts.powerLegal(eruptModel, PowerObject::isAdd);        eruptModifyService.insertEruptData(eruptModel, data);        return R.ok();    }    @SneakyThrows    public void batchAddEruptData(EruptModel eruptModel, List<Object> list) {        for (Object data : list) {            DataProxyInvoke.invoke(eruptModel, (dataProxy -> dataProxy.beforeAdd(data)));        }        DataProcessorManager.getEruptDataProcessor(eruptModel.getClazz()).batchAddData(eruptModel, list);        for (Object obj : list) {            eruptModifyService.modifyLog(eruptModel, "ADD", GsonFactory.getGson().toJson(obj));            DataProxyInvoke.invoke(eruptModel, (dataProxy -> dataProxy.afterAdd(obj)));            applicationEventPublisher.publishEvent(new EruptAddEvent<>(eruptModel.getClazz(), obj));        }    }    @PostMapping("/{erupt}/update")    @EruptRecordOperate(value = "UPDATE", dynamicConfig = EruptRecordNaming.class)    @EruptRouter(skipAuthIndex = 3, authIndex = 1, verifyType = EruptRouter.VerifyType.ERUPT, highSafe = true)    @Transactional    @SneakyThrows    public R<Void> updateEruptData(@PathVariable("erupt") String erupt, @RequestBody JsonObject data) {        EruptModel eruptModel = EruptCoreService.getErupt(erupt);        Erupts.powerLegal(eruptModel, PowerObject::isEdit);        eruptModifyService.updateEruptData(eruptModel, data);        return R.ok();    }    @PostMapping("/{erupt}/delete")    @EruptRouter(skipAuthIndex = 3, authIndex = 1, verifyType = EruptRouter.VerifyType.ERUPT, highSafe = true)    @EruptRecordOperate(value = "DELETE", dynamicConfig = EruptRecordNaming.class)    @Transactional    public R<Void> deleteEruptData(@PathVariable("erupt") String erupt, @RequestBody List<Object> ids) {        EruptModel eruptModel = EruptCoreService.getErupt(erupt);        Erupts.powerLegal(eruptModel, PowerObject::isDelete);        eruptModifyService.deleteEruptData(eruptModel, ids, true);        return R.ok();    }}